     5→/// Find a card by bare id in a state dir, handling glyph-prefixed names.
     6→fn find_card_in(cards: &Path, state: &str, id: &str) -> PathBuf {
     7→    let dir = cards.join(state);
     8→    let suffix = format!("-{}.bop", id);
     9→    let exact = format!("{}.bop", id);
    10→    if dir.join(&exact).exists() {
    11→        return dir.join(exact);
    12→    }
    13→    if let Ok(entries) = fs::read_dir(&dir) {
    14→        for entry in entries.flatten() {
    15→            let name = entry.file_name();
    16→            if name.to_str().map(|n| n.ends_with(&suffix)).unwrap_or(false) {
    17→                return dir.join(name);
    18→            }
    19→        }
    20→    }
    21→    dir.join(exact) // return non-existent path so assert gives useful message
    22→}
