    49→fn send_http_request(port: u16, body: &str) -> String {
    50→    let addr = format!("127.0.0.1:{}", port);
    51→    let request = format!(
    52→        "POST /cards/new HTTP/1.1\r\nHost: {}\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
    53→        addr,
    54→        body.len(),
    55→        body
    56→    );
    57→    let mut stream = TcpStream::connect(&addr).expect("connect to serve");
    58→    stream.write_all(request.as_bytes()).expect("write request");
    59→    let mut response = String::new();
    60→    stream.read_to_string(&mut response).expect("read response");
    61→    response
    62→}
